-- 沙盘下钻全量种子数据
-- 统计周期: 2024-01-01 至 2026-06-30
-- 粒度: 品牌 → 城市 → 商圈(business_area) → 门店

values ('haidilao', '海底捞', '火锅', '全国 KA', '北京', 30, 'KA 城市经理', '深度合作')
on conflict (brand_id) do update set store_count = excluded.store_count;

on conflict (poi_id) do update set
  poi_name = excluded.poi_name, city = excluded.city, district = excluded.district, business_area = excluded.business_area;

delete from public.fact_city_brand_monthly where brand_id = 'haidilao' and month >= '2024-01-01' and month <= '2026-06-30';
on conflict (month, brand_id, city) do update set gmv = excluded.gmv, paid_orders = excluded.paid_orders, verified_orders = excluded.verified_orders;

delete from public.fact_brand_monthly where brand_id = 'haidilao' and month >= '2024-01-01' and month <= '2026-06-30';
on conflict (month, brand_id) do update set gtv = excluded.gtv, paid_orders = excluded.paid_orders;

delete from public.fact_poi_daily where date >= '2024-01-01' and date <= '2026-06-30' and poi_id like 'hdl-%';
on conflict (date, poi_id) do update set exposure = excluded.exposure, visits = excluded.visits;
